import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS attack!')</script>";

        // Properly escaping user input before printing it to the HTML output
        String escapedUserInput = StringEscapeUtils.escapeHtml4(userInput);

        PrintWriter out = new PrintWriter(System.out);
        out.println("<div>" + escapedUserInput + "</div>");
        out.flush();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
